<template>
    <div class="card">
        <div class="row d-flex justify-content-end">
            <button
                @click.prevent="addNewAccount"
                type="button"
                class="btn btn-outline-primary btn-icon btn-icon-start w-100 w-md-auto m-2"
            >
                <span>
                    Agregar nueva cuenta
                </span>
            </button>
        </div>
        <div class="card-header bg-primary mt-1">
            <h6 class="my-0 text-white">Listado de cuentas bancarias</h6>
        </div>
        <div class="card-body">
            <div class="table-responsive">
                <table class="table">
                    <thead>
                        <tr>
                            <th>#</th>
                            <th>Descripción</th>
                            <th class="text-end">Número</th>
                            <th class="text-end">Balance</th>
                            <th class="text-end">Acciones</th>
                        </tr>
                    </thead>
                    <tbody>
                        <tr v-for="(row, index) in records" :key="index">
                            <td>{{ index + 1 }}</td>
                            <td>{{ row.description }}</td>
                            <td class="text-end">{{ row.number }}</td>
                            <td class="text-end">{{ row.balance }}</td>
                            <td class="text-end">
                                <button
                                    type="button"
                                    class="btn waves-effect waves-light btn-sm btn-info"
                                    @click.prevent="clickCreate(row.id)"
                                >
                                    Editar
                                </button>

                                <template
                                    v-if="
                                        typeUser === 'admin' ||
                                            typeUser === 'superadmin'
                                    "
                                >
                                    <button
                                        type="button"
                                        class="btn waves-effect waves-light btn-sm btn-danger"
                                        @click.prevent="clickDelete(row.id)"
                                    >
                                        Eliminar
                                    </button>
                                </template>
                            </td>
                        </tr>
                    </tbody>
                </table>
            </div>
            <div class="row">
                <div class="col">
                    <button
                        type="button"
                        class="btn btn-custom btn-sm  mt-2 mr-2"
                        @click.prevent="clickCreate()"
                    >
                        <i class="fa fa-plus-circle"></i> Nuevo
                    </button>
                </div>
            </div>
        </div>
        <bank-accounts-form
            :showDialog.sync="showDialog"
            :recordId="recordId"
        ></bank-accounts-form>
    </div>
</template>

<script>
import BankAccountsForm from "./form.vue";
import { deletable } from "../../mixins/deletable";

export default {
    mixins: [deletable],
    props: ["typeUser"],
    components: { BankAccountsForm },
    data() {
        return {
            showDialog: false,
            resource: "bank_accounts",
            recordId: null,
            records: [],
        };
    },
    created() {
        this.$eventHub.$on("reloadData", () => {
            this.getData();
        });
        this.getData();
    },
    methods: {
        addNewAccount(){
            this.showDialog = true;
        },
        getData() {
            this.$http.get(`/${this.resource}/records`).then(response => {
                this.records = response.data.data;
            });
        },
        clickCreate(recordId = null) {
            this.recordId = recordId;
            this.showDialog = true;
        },
        clickDelete(id) {
            this.destroy(`/${this.resource}/${id}`).then(() =>
                this.$eventHub.$emit("reloadData")
            );
        }
    }
};
</script>



